/* [getCmmnCodeData] 회사별 공통코드 조회 */
SELECT CASE WHEN A.CODE = '*****' THEN A.CODE_SECTION_CODE ELSE A.CODE END AS NODE_ID , CASE WHEN A.CODE = '*****' THEN A.CODE ELSE A.CODE_SECTION_CODE END AS PARENT_NODE_ID , A.GROUP_CODE , A.CODE , A.CODE_NAME AS CODE_NAME -- 다국어 코드명 , A.CODE_DESC AS CODE_DESC --다국어 코드설명 , A.CODE_SECTION_CODE , A.ETC_01_INFO , A.ETC_02_INFO , A.ETC_03_INFO , A.ETC_04_INFO , A.ETC_05_INFO , A.ETC_06_INFO , A.ETC_07_INFO , A.ETC_08_INFO , A.ETC_09_INFO , A.ETC_10_INFO , A.SORTING_SN FROM VIEW_COM_CODE A WHERE A.COMPANY_CODE = #{sessionCompanyCode} AND A.USE_AT = 'Y' AND A.BEGIN_DATE <= TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDD') AND A.END_DATE >= TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDD') AND A.LANGUAGE_CODE = #{sessionLanguageCode}
AND A.GROUP_CODE = #{groupCode}
GROUP BY A.COMPANY_CODE , A.GROUP_CODE , A.CODE_SECTION_CODE , A.CODE , A.CODE_NAME , A.CODE_DESC , A.ETC_01_INFO , A.ETC_02_INFO , A.ETC_03_INFO , A.ETC_04_INFO , A.ETC_05_INFO , A.ETC_06_INFO , A.ETC_07_INFO , A.ETC_08_INFO , A.ETC_09_INFO , A.ETC_10_INFO , A.BEGIN_DATE , A.END_DATE , A.SORTING_SN , A.USE_AT , A.FIRST_CREATE_USER_ID , A.LAST_UPDATE_USER_ID , A.CREATE_DT , A.UPDATE_DT ORDER BY CASE WHEN A.CODE = '*****' THEN A.CODE ELSE A.CODE_SECTION_CODE END, A.SORTING_SN, A.CODE

/* [getSysCodeData] 시스템 공통코드 조회 */
SELECT CASE WHEN A.CODE = '*****' THEN A.CODE_SECTION_CODE ELSE A.CODE END AS NODE_ID , CASE WHEN A.CODE = '*****' THEN A.CODE ELSE A.CODE_SECTION_CODE END AS PARENT_NODE_ID , A.GROUP_CODE AS GROUP_CODE , A.CODE AS CODE , A.CODE_NAME AS CODE_NAME -- 다국어 코드명 , A.CODE_DESC AS CODE_DESC --다국어 코드설명 , A.CODE_SECTION_CODE AS CODE_SECTION_CODE , A.ETC_01_INFO AS ETC_01_INFO , A.ETC_02_INFO AS ETC_02_INFO , A.ETC_03_INFO AS ETC_03_INFO , A.ETC_04_INFO AS ETC_04_INFO , A.ETC_05_INFO AS ETC_05_INFO , A.ETC_06_INFO AS ETC_06_INFO , A.ETC_07_INFO AS ETC_07_INFO , A.ETC_08_INFO AS ETC_08_INFO , A.ETC_09_INFO AS ETC_09_INFO , A.ETC_10_INFO AS ETC_10_INFO , A.SORTING_SN FROM VIEW_COM_SYS_CODE A WHERE A.USE_AT = 'Y' AND A.BEGIN_DATE <= TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDD') AND A.END_DATE >= TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDD')
AND A.LANGUAGE_CODE = #{languageCode}
AND A.LANGUAGE_CODE = #{sessionLanguageCode}
AND A.GROUP_CODE = #{groupCode}
ORDER BY CASE WHEN A.CODE = '*****' THEN A.CODE ELSE A.CODE_SECTION_CODE END, A.SORTING_SN, A.CODE

/* [getCmmnCodeDataByGroupCodeList] 멀티 그룹코드 기준 리스트 검색 */
SELECT GROUP_CODE , CODE , CODE_NAME , CODE_SECTION_CODE , ETC_01_INFO , ETC_02_INFO , ETC_03_INFO , ETC_04_INFO , ETC_05_INFO , CODE_DESC , SORTING_SN FROM VIEW_COM_CODE WHERE COMPANY_CODE = #{sessionCompanyCode} AND CODE != '*****' AND USE_AT = 'Y' AND BEGIN_DATE <= TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDD') AND END_DATE >= TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDD') AND LANGUAGE_CODE = #{sessionLanguageCode}
AND GROUP_CODE IN
#{groupCode, jdbcType=VARCHAR}
UNION ALL
SELECT GROUP_CODE , CODE , CODE_NAME , CODE_SECTION_CODE , ETC_01_INFO , ETC_02_INFO , ETC_03_INFO , ETC_04_INFO , ETC_05_INFO , CODE_DESC , SORTING_SN FROM VIEW_COM_SYS_CODE WHERE CODE != '*****' AND USE_AT = 'Y' AND BEGIN_DATE <= TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDD') AND END_DATE >= TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDD') AND LANGUAGE_CODE = #{sessionLanguageCode}
AND GROUP_CODE IN
#{groupCode, jdbcType=VARCHAR}
ORDER BY CODE_SECTION_CODE, SORTING_SN, CODE

/* [getAuthMenuTreeData] 권한이 적용된 메뉴 트리 검색 */
WITH RECURSIVE CTE_AUTH_MENU(MAIN_MENU_KEY, MENU_KEY, UPPER_MENU_KEY, SCREEN_VISIBLE_AT) AS ( SELECT MAX(CASE WHEN AA.PRIOR_RANK = 1 THEN AA.MAIN_MENU_KEY ELSE NULL END) OVER() AS MAIN_MENU_KEY , BB.MENU_KEY , BB.UPPER_MENU_KEY , BB.SCREEN_VISIBLE_AT FROM ( SELECT A.COMPANY_CODE , ROW_NUMBER() OVER(ORDER BY B.PRIOR_RANK) AS PRIOR_RANK , D.MENU_KEY , MAX(B.MAIN_MENU_KEY) AS MAIN_MENU_KEY FROM COM_USER A INNER JOIN COM_AUTH_GROUP B ON A.COMPANY_CODE = B.COMPANY_CODE INNER JOIN COM_AUTH_GROUP_USER C ON A.COMPANY_CODE = C.COMPANY_CODE AND A.USER_ID = C.USER_ID AND B.GROUP_KEY = C.GROUP_KEY INNER JOIN COM_AUTH_GROUP_MENU D ON A.COMPANY_CODE = D.COMPANY_CODE AND B.GROUP_KEY = D.GROUP_KEY WHERE A.COMPANY_CODE = #{sessionCompanyCode} AND A.USER_ID = #{sessionUserId} GROUP BY A.COMPANY_CODE, B.PRIOR_RANK, D.MENU_KEY ) AA INNER JOIN COM_MENU BB ON AA.COMPANY_CODE = BB.COMPANY_CODE AND AA.MENU_KEY = BB.MENU_KEY UNION ALL SELECT NULL , A.MENU_KEY , A.UPPER_MENU_KEY , A.SCREEN_VISIBLE_AT FROM COM_MENU A INNER JOIN CTE_AUTH_MENU B ON A.MENU_KEY = B.UPPER_MENU_KEY WHERE A.COMPANY_CODE = #{sessionCompanyCode} )
SELECT MAX(CASE WHEN AA.USER_MAIN_MENU_KEY IS NULL THEN AA.MAIN_MENU_KEY ELSE AA.USER_MAIN_MENU_KEY END) OVER() AS MAIN_MENU_KEY , AA.MENU_KEY , AA.FULL_MENU_KEY , AA.FULL_MENU_NAME , AA.MENU_NAME , AA.NODE_LEVEL , AA.UPPER_MENU_KEY , AA.MENU_DESC , AA.PROGRAM_PARAM_CONTENTS , AA.VIEW_TARGET_CODE , AA.MENU_PATH_INFO , AA.POPUP_WIDTH_SIZE , AA.POPUP_VERTICAL_SIZE , AA.ICON_CLASS_NAME , AA.HAS_CHILD_AT , CASE WHEN DD.MENU_KEY IS NOT NULL THEN 'Y' ELSE 'N' END AS FAVORITE_AT , CASE WHEN DD.MENU_KEY IS NOT NULL THEN DD.SORTING_SN ELSE 0 END AS FAVORITE_SORTING_SN , AA.SCREEN_VISIBLE_AT FROM ( SELECT DISTINCT MAX(B.MAIN_MENU_KEY) OVER() AS MAIN_MENU_KEY , MAX(C.MAIN_MENU_KEY) OVER() AS USER_MAIN_MENU_KEY , A.MENU_KEY AS MENU_KEY , A.FULL_MENU_KEY AS FULL_MENU_KEY , A.FULL_MENU_NAME AS FULL_MENU_NAME , A.MENU_NAME AS MENU_NAME , A.NODE_LEVEL AS NODE_LEVEL , A.UPPER_MENU_KEY AS UPPER_MENU_KEY , A.MENU_DESC AS MENU_DESC , A.PROGRAM_PARAM_CONTENTS AS PROGRAM_PARAM_CONTENTS , A.VIEW_TARGET_CODE AS VIEW_TARGET_CODE , A.MENU_PATH_INFO AS MENU_PATH_INFO , A.POPUP_WIDTH_SIZE AS POPUP_WIDTH_SIZE , A.POPUP_VERTICAL_SIZE AS POPUP_VERTICAL_SIZE , A.ICON_CLASS_NAME AS ICON_CLASS_NAME , A.CUSTOM_SORTING_SN AS CUSTOM_SORTING_SN , #{sessionOriginCompanyCode} AS COMPANY_CODE , #{sessionCompanyCode} AS TARGET_COMPANY_CODE , CASE WHEN (SELECT COUNT(MENU_KEY) FROM COM_MENU WHERE UPPER_MENU_KEY = A.MENU_KEY) > 0 THEN 'Y' ELSE 'N' END AS HAS_CHILD_AT , A.SCREEN_VISIBLE_AT FROM VIEW_MENU_INFO A INNER JOIN CTE_AUTH_MENU B ON A.MENU_KEY = B.MENU_KEY LEFT OUTER JOIN COM_USER C ON B.MENU_KEY = C.MAIN_MENU_KEY AND C.COMPANY_CODE = #{sessionCompanyCode} AND C.USER_ID = #{sessionUserId} WHERE A.COMPANY_CODE = #{sessionCompanyCode} AND A.FULL_USE_AT NOT LIKE '%N%' -- TODO: 사용 여부 TREE 중 N이 포함된 케이스에 대응하기 위한 인덱스 추가 AND A.LANGUAGE_CODE = #{sessionLanguageCode}
AND A.SOLUTION_SECTION_CODE = #{solutionSectionCode}
) AA LEFT OUTER JOIN COM_COMPANY BB ON AA.COMPANY_CODE = BB.COMPANY_CODE LEFT OUTER JOIN COM_USER_BOOKMARK DD ON AA.MENU_KEY = DD.MENU_KEY AND DD.COMPANY_CODE = #{sessionCompanyCode} AND DD.USER_ID = #{sessionUserId} ORDER BY CUSTOM_SORTING_SN

