/* [selectDeptData] 공통js에서 부서 정보 조회 */
SELECT A.DEPT_CODE
     , A.DEPT_NAME
  FROM (
         SELECT DEPT_CODE
              , DEPT_NAME
           FROM VIEW_DEPT_INFO
          WHERE COMPANY_CODE     = #{sessionCompanyCode}

            AND ( DEPT_CODE LIKE '%' || #{deptInfo} || '%'
             OR   DEPT_NAME LIKE '%' || #{deptInfo} || '%' )


            AND USE_AT           = #{useAt}

       ) A
 WHERE 1 = 1

/* [selectUserData] 공통 사용자 정보 조회 */
SELECT A.USER_ID                  AS USER_ID
     , A.USER_NAME                AS USER_NAME
  FROM COM_USER A
 WHERE A.COMPANY_CODE            = #{sessionCompanyCode}

   AND ( A.USER_ID   LIKE '%' || #{userInfo} || '%'
    OR   A.USER_NAME LIKE '%' || #{userInfo} || '%' )


   AND A.ACCOUNT_USE_AT          = #{accountUseAt}

/* [selectCustomerData] 공통 고객 정보 조회 */
SELECT PU_CODE
     , CUST_CODE
     , CUST_NAME
     , GLOBAL_CUST_NAME
     , CUST_NATION_CODE
     , REGION_CODE
  FROM VOB_CUSTOMER
 WHERE 1=1
   AND COMPANY_CODE       = #{sessionCompanyCode}

   AND ( CUST_CODE        LIKE '%' || #{custInfo} || '%'
    OR   CUST_NAME        LIKE '%' || #{custInfo} || '%'
    OR   GLOBAL_CUST_NAME LIKE '%' || #{custInfo} || '%'
       )


   AND PU_CODE            = #{puCode}


   AND CUST_NATION_CODE   = #{nationCode}


   AND REGION_CODE        = #{regionCode}

 ORDER BY CUST_NAME

