mapper.select:
/* [selectCorpCode] PU 권한이 적용된 공통 CORP (법인 회사) 정보 조회 */
SELECT A.SAP_CORP_CODE                      AS NODE_ID
     , '*****'                              AS PARENT_NODE_ID
     , A.SAP_CORP_CODE                      AS CODE
     , B.SAP_CORP_NAME                      AS CODE_NAME
     , '1'                                  AS NODE_LEVEL
  FROM VOB_AUTH_DATA_USER A
 INNER JOIN VOB_CORP_LANG B
    ON A.COMPANY_CODE   = B.COMPANY_CODE
   AND A.SAP_CORP_CODE  = B.SAP_CORP_CODE
   AND B.LANGUAGE_CODE  = #{sessionLanguageCode}
  WHERE A.USER_ID       = #{sessionUserId}
   AND A.PU_CODE        = #{puCode}
   AND A.COMPANY_CODE   = #{sessionCompanyCode} 
 ORDER BY A.CORP_CODE

/* [selectMessageData] 다국어 데이터를 조회한다. */
SELECT MESSAGE_ID
     , LANGUAGE_CODE
     , MESSAGE_CONTENTS
     , USE_AT
  FROM COM_MESSAGE_LANG
 WHERE USE_AT        = 'Y'

   AND LANGUAGE_CODE = #{languageCode}


   AND LANGUAGE_CODE = #{sessionLanguageCode}


   AND MESSAGE_ID    = #{messageId}
